<form [formGroup]="reservationForm" (ngSubmit)="onSubmit()" class="container p-0">
  <div class="row mb-3 align-items-center">
    <label for="guestName" class="col-sm-1 col-form-label">Name:</label>
    <div class="col-sm-10">
      <div class="row g-2 align-items-center">
        <div class="col-5">
          <input id="guestName" formControlName="guestName" required class="form-control">
        </div>
        <div class="col-5">
          <div class="text-danger small" *ngIf="reservationForm.get('guestName')?.invalid && reservationForm.get('guestName')?.touched">
            Name is required.
          </div>
        </div>
      </div>
    </div>
  </div>

  <div class="row mb-3 align-items-center">
    <label for="guestEmail" class="col-sm-1 col-form-label">Email:</label>
    <div class="col-sm-10">
      <div class="row g-2 align-items-center">
        <div class="col-5">
          <input id="guestEmail" formControlName="guestEmail" required type="email" class="form-control">
        </div>
        <div class="col-5">
          <div class="text-danger small" *ngIf="reservationForm.get('guestEmail')?.invalid && reservationForm.get('guestEmail')?.touched">
            Please enter a valid email.
          </div>
        </div>
      </div>
    </div>
  </div>

  <div class="row mb-3 align-items-center">
    <label for="checkInDate" class="col-sm-1 col-form-label">Check-in Date:</label>
    <div class="col-sm-10">
      <div class="row g-2 align-items-center">
        <div class="col-5">
          <input id="checkInDate" formControlName="checkInDate" required type="date" class="form-control">
        </div>
        <div class="col-5">
          <div class="text-danger small" *ngIf="reservationForm.get('checkInDate')?.invalid && reservationForm.get('checkInDate')?.touched">
            Check-in date is required.
          </div>
        </div>
      </div>
    </div>
  </div>

  <div class="row mb-3 align-items-center">
    <label for="checkOutDate" class="col-sm-1 col-form-label">Check-out Date:</label>
    <div class="col-sm-10">
      <div class="row g-2 align-items-center">
        <div class="col-5">
          <input id="checkOutDate" formControlName="checkOutDate" required type="date" class="form-control">
        </div>
        <div class="col-5">
          <div class="text-danger small" *ngIf="reservationForm.get('checkOutDate')?.invalid && reservationForm.get('checkOutDate')?.touched">
            Check-out date is required.
          </div>
        </div>
      </div>
    </div>
  </div>

    <div class="row mb-3 align-items-center">
    <label for="roomNumber" class="col-sm-1 col-form-label">Room Number:</label>
    <div class="col-sm-10">
      <div class="row g-2 align-items-center">
        <div class="col-5">
          <input id="roomNumber" formControlName="roomNumber" required class="form-control">
        </div>
        <div class="col-5">
          <div class="text-danger small" *ngIf="reservationForm.get('roomNumber')?.invalid && reservationForm.get('roomNumber')?.touched">
            Room number is required.
          </div>
        </div>
      </div>
    </div>
  </div>

  <button type="submit" [disabled]="reservationForm.invalid" class="btn btn-primary">Submit Reservation</button>

</form>
